argus_load_root_env() {
  if [ -f .env ]; then
    set -a
    set +u
    # shellcheck disable=SC1091
    source .env
    set -u
    set +a
    return 0
  fi
  return 1
}

argus_require_env() {
  local name="$1"
  local value
  local had_nounset=0

  case "$-" in
    *u*)
      had_nounset=1
      set +u
      ;;
  esac
  value="${!name}"
  if [ "$had_nounset" -eq 1 ]; then
    set -u
  fi

  if [ -z "$value" ] || [[ "$value" == YOUR_* ]] || [[ "$value" == your_* ]]; then
    echo "❌ $name is required."
    exit 1
  fi
}

argus_require_qa_env() {
  local name
  for name in "${ARGUS_QA_REQUIRED_ENV[@]}"; do
    argus_require_env "$name"
  done
}

argus_export_dev_mode() {
  export ARGUS_PERSISTENCE_MODE=memory
  export ARGUS_DEV_MEMORY_FALLBACK=true
  export ARGUS_MARKET_DATA_PROVIDER_MODE=synthetic_unit_fixture
  export ARGUS_CHECKPOINTER_MODE=memory
  export ARGUS_MOCK_AUTH=true
  # Skip the onboarding gate in dev so memory-mode restarts don't re-prompt for it.
  export ARGUS_PRIVATE_ALPHA_ONBOARDING_ENABLED=false
  export ENABLE_MARKET_DATA_CACHE=false
  export ARGUS_BACKTEST_JOBS_SHADOW_ENABLED=false
  export ARGUS_BACKTEST_JOBS_DISPATCH_ENABLED=false
