  export ARGUS_BACKTEST_JOBS_GLOBAL_RUNNING_LIMIT=5
  export ARGUS_BACKTEST_JOBS_GLOBAL_QUEUED_LIMIT=10
  export ARGUS_CONTEXT_PACKETS_ENABLED=false
  unset DATABASE_URL
}

